// Fetch analytics stats from each platform for the current batch of shorts
const shorts = $input.all().map(item => item.json);
const results = [];

for (const short of shorts) {
  const stats = { id: short.id, topic_id: short.topic_id, project_id: short.project_id };

  // TikTok stats
  if (short.tiktok_status === 'published' && short.tiktok_post_id && process.env.TIKTOK_ACCESS_TOKEN) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://open.tiktokapis.com/v2/video/query/',
        headers: {
          'Authorization': `Bearer ${process.env.TIKTOK_ACCESS_TOKEN}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          filters: { video_ids: [short.tiktok_post_id] },
          fields: ['view_count', 'like_count', 'comment_count', 'share_count'],
        }),
      });
      const video = resp?.data?.videos?.[0];
      if (video) {
        stats.tiktok_views = video.view_count || 0;
        stats.tiktok_likes = video.like_count || 0;
        stats.tiktok_comments = video.comment_count || 0;
        stats.tiktok_shares = video.share_count || 0;
      }
    } catch (e) { /* continue */ }
  }

  // Instagram stats
  if (short.instagram_status === 'published' && short.instagram_post_id && process.env.INSTAGRAM_ACCESS_TOKEN) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://graph.facebook.com/v19.0/${short.instagram_post_id}/insights?metric=plays,likes,comments&access_token=${process.env.INSTAGRAM_ACCESS_TOKEN}`,
      });
      const metrics = resp?.data || [];
      for (const m of metrics) {
        if (m.name === 'plays') stats.instagram_views = m.values?.[0]?.value || 0;
        if (m.name === 'likes') stats.instagram_likes = m.values?.[0]?.value || 0;
        if (m.name === 'comments') stats.instagram_comments = m.values?.[0]?.value || 0;
      }
    } catch (e) { /* continue */ }
  }

  // YouTube Shorts stats
  if (short.youtube_shorts_status === 'published' && short.youtube_shorts_video_id && process.env.YOUTUBE_API_KEY) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://www.googleapis.com/youtube/v3/videos?part=statistics&id=${short.youtube_shorts_video_id}&key=${process.env.YOUTUBE_API_KEY}`,
      });
      const video = resp?.items?.[0]?.statistics;
      if (video) {
        stats.youtube_shorts_views = parseInt(video.viewCount) || 0;
        stats.youtube_shorts_likes = parseInt(video.likeCount) || 0;
      }
    } catch (e) { /* continue */ }
  }

  results.push(stats);
}

return results.map(r => ({ json: r }));

// PATCH each short with fetched analytics stats
const items = $input.all();
let updated = 0;

for (const item of items) {
  const s = item.json;
  const patchBody = {};

  // Only include fields that were actually fetched
  if (s.tiktok_views !== undefined) patchBody.tiktok_views = s.tiktok_views;
  if (s.tiktok_likes !== undefined) patchBody.tiktok_likes = s.tiktok_likes;
  if (s.tiktok_comments !== undefined) patchBody.tiktok_comments = s.tiktok_comments;
  if (s.tiktok_shares !== undefined) patchBody.tiktok_shares = s.tiktok_shares;
  if (s.instagram_views !== undefined) patchBody.instagram_views = s.instagram_views;
  if (s.instagram_likes !== undefined) patchBody.instagram_likes = s.instagram_likes;
  if (s.instagram_comments !== undefined) patchBody.instagram_comments = s.instagram_comments;
  if (s.youtube_shorts_views !== undefined) patchBody.youtube_shorts_views = s.youtube_shorts_views;
  if (s.youtube_shorts_likes !== undefined) patchBody.youtube_shorts_likes = s.youtube_shorts_likes;

  if (Object.keys(patchBody).length === 0) continue;

  patchBody.updated_at = new Date().toISOString();

  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${process.env.SUPABASE_URL}/rest/v1/shorts?id=eq.${s.id}`,
      headers: {
        'apikey': process.env.SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
      },
      body: JSON.stringify(patchBody),
    });
    updated++;
  } catch (e) { /* continue with next */ }
}

return [{ json: { updated, total: items.length } }];

// Handle errors during analytics refresh
const error = $input.first().json;
const errorMsg = error?.message || error?.error || 'Unknown error during analytics refresh';

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/production_logs`,
    headers: {
      'apikey': process.env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: JSON.stringify({ stage: 'social_analytics', action: 'analytics_refresh_failed', status: 'error', details: { error: errorMsg } }),
  });
} catch (e) { /* best effort */ }

return [{ json: { error: errorMsg, status: 'failed' } }];

